
UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=XmrPk4pXKqw',
  conteudo_texto = '<h2>Interpretação de Textos em Inglês</h2><p>Estratégias para compreensão de textos técnicos em provas de concursos.</p><h3>📖 Tipos de Questões</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>O que pede</th><th style=''padding:10px;border:1px solid #ddd;''>Dica</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Ideia Principal</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Main idea, purpose</td><td style=''padding:10px;border:1px solid #ddd;''>Leia primeiro e último parágrafo</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Detalhes</strong></td><td style=''padding:10px;border:1px solid #ddd;''>According to the text...</td><td style=''padding:10px;border:1px solid #ddd;''>Localize palavras-chave</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Inferência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>It can be inferred...</td><td style=''padding:10px;border:1px solid #ddd;''>Conclusão lógica do texto</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Vocabulário</strong></td><td style=''padding:10px;border:1px solid #ddd;''>The word X means...</td><td style=''padding:10px;border:1px solid #ddd;''>Use o contexto</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Referência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>The pronoun IT refers to...</td><td style=''padding:10px;border:1px solid #ddd;''>Volte no texto</td></tr></table></div><h3>🎯 Estratégia de Leitura</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>1️⃣ Skimming</h4><p>Leitura rápida para ideia geral</p><ul><li>Título</li><li>Subtítulos</li><li>Primeiro parágrafo</li><li>Palavras em destaque</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>2️⃣ Scanning</h4><p>Busca por informação específica</p><ul><li>Números</li><li>Nomes</li><li>Datas</li><li>Palavras-chave</li></ul></div></div><h3>🔗 Conectivos Importantes</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Conectivos</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Adição</strong></td><td style=''padding:10px;border:1px solid #ddd;''>moreover, furthermore, in addition, besides</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Contraste</strong></td><td style=''padding:10px;border:1px solid #ddd;''>however, nevertheless, although, despite, whereas</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Causa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>because, since, due to, owing to</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Consequência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>therefore, thus, consequently, as a result</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Exemplo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>for instance, for example, such as</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Conclusão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>in conclusion, to sum up, finally</td></tr></table></div><h3>⚠️ Armadilhas Comuns</h3><div style=''background:#f8d7da;padding:15px;border-radius:8px;margin:15px 0;''><ul><li>❌ Alternativas com palavras do texto mas sentido diferente</li><li>❌ Generalizações excessivas (all, never, always)</li><li>❌ Informações verdadeiras mas não mencionadas no texto</li><li>❌ Tradução literal de expressões idiomáticas</li></ul></div><h3>📝 Cognatos × Falsos Cognatos</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>✅ Cognatos (ajudam)</h4><ul><li>important = importante</li><li>economy = economia</li><li>temperature = temperatura</li><li>production = produção</li></ul></div><div style=''flex:1;min-width:200px;background:#f8d7da;padding:15px;border-radius:8px;''><h4>❌ Falsos Cognatos</h4><ul><li>actually = na verdade</li><li>eventually = finalmente</li><li>pretend = fingir</li><li>push = empurrar</li></ul></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Leia as <strong>perguntas ANTES</strong> do texto! Assim você sabe o que procurar e otimiza o tempo.</p></div>'
WHERE titulo = 'Resumo: Interpretação de Textos';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=T_5AdLdK6Gc',
  conteudo_texto = '<h2>Gramática Essencial</h2><p>Tempos verbais, preposições e conectivos mais cobrados em provas.</p><h3>⏰ Tempos Verbais</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tempo</th><th style=''padding:10px;border:1px solid #ddd;''>Estrutura</th><th style=''padding:10px;border:1px solid #ddd;''>Uso</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Simple Present</strong></td><td style=''padding:10px;border:1px solid #ddd;''>V / V+s</td><td style=''padding:10px;border:1px solid #ddd;''>Rotinas, fatos</td><td style=''padding:10px;border:1px solid #ddd;''>Oil floats on water</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Simple Past</strong></td><td style=''padding:10px;border:1px solid #ddd;''>V+ed / irregular</td><td style=''padding:10px;border:1px solid #ddd;''>Ação concluída</td><td style=''padding:10px;border:1px solid #ddd;''>Petrobras discovered oil</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Present Perfect</strong></td><td style=''padding:10px;border:1px solid #ddd;''>have/has + V3</td><td style=''padding:10px;border:1px solid #ddd;''>Passado → presente</td><td style=''padding:10px;border:1px solid #ddd;''>Production has increased</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Past Perfect</strong></td><td style=''padding:10px;border:1px solid #ddd;''>had + V3</td><td style=''padding:10px;border:1px solid #ddd;''>Antes de outro passado</td><td style=''padding:10px;border:1px solid #ddd;''>They had finished before</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Future (will)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>will + V</td><td style=''padding:10px;border:1px solid #ddd;''>Previsões, decisões</td><td style=''padding:10px;border:1px solid #ddd;''>Prices will rise</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Going to</strong></td><td style=''padding:10px;border:1px solid #ddd;''>be going to + V</td><td style=''padding:10px;border:1px solid #ddd;''>Planos, evidências</td><td style=''padding:10px;border:1px solid #ddd;''>It is going to rain</td></tr></table></div><h3>🔄 Voz Passiva</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><h4>Estrutura: be + past participle (V3)</h4><table style=''width:100%;border-collapse:collapse;margin-top:10px;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tempo</th><th style=''padding:10px;border:1px solid #ddd;''>Passiva</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Present</td><td style=''padding:10px;border:1px solid #ddd;''>is/are + V3</td><td style=''padding:10px;border:1px solid #ddd;''>Oil <strong>is extracted</strong> daily</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>Past</td><td style=''padding:10px;border:1px solid #ddd;''>was/were + V3</td><td style=''padding:10px;border:1px solid #ddd;''>The well <strong>was drilled</strong></td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Future</td><td style=''padding:10px;border:1px solid #ddd;''>will be + V3</td><td style=''padding:10px;border:1px solid #ddd;''>It <strong>will be completed</strong></td></tr></table><p style=''margin-top:10px;''><em>Muito comum em textos técnicos! O foco é na ação, não em quem faz.</em></p></div><h3>📍 Preposições</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#17a2b8;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Preposição</th><th style=''padding:10px;border:1px solid #ddd;''>Uso</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>in</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Meses, anos, países, cidades grandes</td><td style=''padding:10px;border:1px solid #ddd;''>in Brazil, in 2024, in January</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>on</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Dias, datas, superfícies</td><td style=''padding:10px;border:1px solid #ddd;''>on Monday, on the platform</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>at</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Horas, locais específicos</td><td style=''padding:10px;border:1px solid #ddd;''>at 9 AM, at the refinery</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>by</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Agente, meio, prazo</td><td style=''padding:10px;border:1px solid #ddd;''>by Petrobras, by 2030</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>for</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Duração, propósito</td><td style=''padding:10px;border:1px solid #ddd;''>for 10 years, for safety</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>since</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Ponto inicial no tempo</td><td style=''padding:10px;border:1px solid #ddd;''>since 2010</td></tr></table></div><h3>❓ Modais</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Modal</th><th style=''padding:10px;border:1px solid #ddd;''>Significado</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>can/could</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Capacidade, possibilidade</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>may/might</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Possibilidade, permissão</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>must</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Obrigação, certeza</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>should</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conselho, recomendação</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>would</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Condicional, educação</td></tr></table></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A <strong>voz passiva</strong> é muito usada em textos técnicos de petróleo. Identifique: <strong>be + particípio passado</strong>!</p></div>'
WHERE titulo = 'Resumo: Gramática Essencial';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=R8g8QT4z7GI',
  conteudo_texto = '<h2>Vocabulário Técnico</h2><p>Termos essenciais de petróleo e gás para provas da Petrobras.</p><h3>🛢️ Exploração e Produção (E&P)</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Inglês</th><th style=''padding:10px;border:1px solid #ddd;''>Português</th><th style=''padding:10px;border:1px solid #ddd;''>Contexto</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>drilling</strong></td><td style=''padding:10px;border:1px solid #ddd;''>perfuração</td><td style=''padding:10px;border:1px solid #ddd;''>drilling rig = sonda</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>well</strong></td><td style=''padding:10px;border:1px solid #ddd;''>poço</td><td style=''padding:10px;border:1px solid #ddd;''>oil well, gas well</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>reservoir</strong></td><td style=''padding:10px;border:1px solid #ddd;''>reservatório</td><td style=''padding:10px;border:1px solid #ddd;''>rock reservoir</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>offshore</strong></td><td style=''padding:10px;border:1px solid #ddd;''>mar/costa</td><td style=''padding:10px;border:1px solid #ddd;''>offshore platform</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>onshore</strong></td><td style=''padding:10px;border:1px solid #ddd;''>terra</td><td style=''padding:10px;border:1px solid #ddd;''>onshore field</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>pre-salt</strong></td><td style=''padding:10px;border:1px solid #ddd;''>pré-sal</td><td style=''padding:10px;border:1px solid #ddd;''>pre-salt layer</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>barrel (bbl)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>barril</td><td style=''padding:10px;border:1px solid #ddd;''>159 litros</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>crude oil</strong></td><td style=''padding:10px;border:1px solid #ddd;''>petróleo bruto</td><td style=''padding:10px;border:1px solid #ddd;''>crude oil extraction</td></tr></table></div><h3>🏭 Refino e Processamento</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Inglês</th><th style=''padding:10px;border:1px solid #ddd;''>Português</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>refinery</strong></td><td style=''padding:10px;border:1px solid #ddd;''>refinaria</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>distillation</strong></td><td style=''padding:10px;border:1px solid #ddd;''>destilação</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>cracking</strong></td><td style=''padding:10px;border:1px solid #ddd;''>craqueamento</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>gasoline</strong></td><td style=''padding:10px;border:1px solid #ddd;''>gasolina</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>diesel</strong></td><td style=''padding:10px;border:1px solid #ddd;''>diesel</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>jet fuel</strong></td><td style=''padding:10px;border:1px solid #ddd;''>querosene de aviação</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>LPG</strong></td><td style=''padding:10px;border:1px solid #ddd;''>GLP (gás de cozinha)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>pipeline</strong></td><td style=''padding:10px;border:1px solid #ddd;''>oleoduto/gasoduto</td></tr></table></div><h3>🔧 Equipamentos</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><ul><li><strong>pump</strong> = bomba</li><li><strong>valve</strong> = válvula</li><li><strong>compressor</strong> = compressor</li><li><strong>tank</strong> = tanque</li><li><strong>vessel</strong> = vaso/navio</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><ul><li><strong>BOP</strong> = Blowout Preventer</li><li><strong>FPSO</strong> = navio-plataforma</li><li><strong>riser</strong> = coluna de produção</li><li><strong>casing</strong> = revestimento</li><li><strong>bit</strong> = broca</li></ul></div></div><h3>📊 Termos de Negócios</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Inglês</th><th style=''padding:10px;border:1px solid #ddd;''>Português</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>bid</strong></td><td style=''padding:10px;border:1px solid #ddd;''>licitação/lance</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>stakeholder</strong></td><td style=''padding:10px;border:1px solid #ddd;''>parte interessada</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>supply chain</strong></td><td style=''padding:10px;border:1px solid #ddd;''>cadeia de suprimentos</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>output</strong></td><td style=''padding:10px;border:1px solid #ddd;''>produção/saída</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>throughput</strong></td><td style=''padding:10px;border:1px solid #ddd;''>vazão/capacidade</td></tr></table></div><h3>🌱 Meio Ambiente</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>emission = emissão</span><span style=''background:#17a2b8;color:white;padding:8px 12px;border-radius:20px;''>spill = vazamento</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>waste = resíduo</span><span style=''background:#dc3545;color:white;padding:8px 12px;border-radius:20px;''>leak = fuga</span><span style=''background:#6f42c1;color:white;padding:8px 12px;border-radius:20px;''>renewable = renovável</span></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Memorize: <strong>upstream</strong> (exploração/produção) × <strong>downstream</strong> (refino/distribuição) × <strong>midstream</strong> (transporte)!</p></div>'
WHERE titulo = 'Resumo: Vocabulário Técnico';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=6C7gB8uX6wE',
  conteudo_texto = '<h2>Inglês para Negócios</h2><p>Comunicação empresarial em inglês para ambiente corporativo.</p><h3>📧 E-mails Corporativos</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Parte</th><th style=''padding:10px;border:1px solid #ddd;''>Formal</th><th style=''padding:10px;border:1px solid #ddd;''>Menos Formal</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Saudação</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Dear Mr./Ms. + sobrenome</td><td style=''padding:10px;border:1px solid #ddd;''>Hi + nome</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Abertura</strong></td><td style=''padding:10px;border:1px solid #ddd;''>I am writing to inform you...</td><td style=''padding:10px;border:1px solid #ddd;''>Just wanted to let you know...</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Pedido</strong></td><td style=''padding:10px;border:1px solid #ddd;''>I would appreciate if you could...</td><td style=''padding:10px;border:1px solid #ddd;''>Could you please...</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Fechamento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Best regards / Sincerely</td><td style=''padding:10px;border:1px solid #ddd;''>Best / Thanks</td></tr></table></div><h3>📞 Expressões de Reunião</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Iniciar</h4><ul><li>Let''s get started</li><li>Shall we begin?</li><li>The purpose of this meeting is...</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Opinar</h4><ul><li>In my opinion...</li><li>I believe that...</li><li>From my point of view...</li></ul></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>Encerrar</h4><ul><li>To sum up...</li><li>Let''s wrap up</li><li>Any final questions?</li></ul></div></div><h3>📊 Apresentações</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Expressão</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Introdução</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Today I''m going to talk about...</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Estrutura</strong></td><td style=''padding:10px;border:1px solid #ddd;''>I''ve divided my presentation into three parts...</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Transição</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Moving on to... / Let''s now look at...</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Gráficos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>As you can see in this chart...</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Conclusão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>In conclusion... / To summarize...</td></tr></table></div><h3>💼 Vocabulário Corporativo</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#6c757d;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Inglês</th><th style=''padding:10px;border:1px solid #ddd;''>Português</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>deadline</strong></td><td style=''padding:10px;border:1px solid #ddd;''>prazo</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>feedback</strong></td><td style=''padding:10px;border:1px solid #ddd;''>retorno/comentário</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>benchmark</strong></td><td style=''padding:10px;border:1px solid #ddd;''>referência/padrão</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>milestone</strong></td><td style=''padding:10px;border:1px solid #ddd;''>marco/etapa</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>KPI</strong></td><td style=''padding:10px;border:1px solid #ddd;''>indicador-chave</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>ROI</strong></td><td style=''padding:10px;border:1px solid #ddd;''>retorno sobre investimento</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>ASAP</strong></td><td style=''padding:10px;border:1px solid #ddd;''>o mais rápido possível</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>FYI</strong></td><td style=''padding:10px;border:1px solid #ddd;''>para sua informação</td></tr></table></div><h3>🤝 Negociação</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#007bff;color:white;padding:8px 12px;border-radius:20px;''>deal = acordo</span><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>bid = proposta</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>quote = cotação</span><span style=''background:#dc3545;color:white;padding:8px 12px;border-radius:20px;''>contract = contrato</span><span style=''background:#6f42c1;color:white;padding:8px 12px;border-radius:20px;''>terms = termos</span></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Em textos de negócios, atenção aos <strong>phrasal verbs</strong>: carry out (executar), set up (estabelecer), look into (investigar), bring up (mencionar)!</p></div>'
WHERE titulo = 'Resumo: Inglês para Negócios';
